import type {GameBuildInfo} from "./GameBuildInfo.js";

// "valid" is about whether packageRoot/package.json could be read at all — it says nothing about
// whether the package was generated by "pokie build" (see "generated"/"buildInfo" for that). A
// package that's perfectly valid but hand-written (e.g. from "pokie create") is still "valid: true",
// "generated: false".
export type GamePackageInspectionReport = {
    packageRoot: string;
    valid: boolean;
    error?: string;
    packageJson?: {name?: string; version?: string; description?: string};
    generated: boolean;
    buildInfo?: GameBuildInfo;
};
